const msg = $input.first().json.message || {};
const chatId = msg.chat?.id;
const text = (msg.text || '').trim();
const cmd = text.replace(/^\/statement\s*/i, '').trim().toLowerCase();

const monthNames = ['january','february','march','april','may','june','july','august','september','october','november','december'];
const monthShort = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];

const now = new Date();
const todayStr = now.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });

let startDate, endDate, periodLabel;
let matchedMonth = -1;
let matchedYear = null;

const yearMatch = cmd.match(/\b(20\d{2})\b/);
if (yearMatch) matchedYear = parseInt(yearMatch[1]);

for (let i = 0; i < 12; i++) {
  if (cmd.includes(monthNames[i]) || cmd.includes(monthShort[i])) {
    matchedMonth = i; break;
  }
}

if (matchedMonth >= 0) {
  const year = matchedYear || now.getFullYear();
  startDate = `${year}-${String(matchedMonth + 1).padStart(2, '0')}-01`;
  const lastDay = new Date(year, matchedMonth + 1, 0).getDate();
  endDate = `${year}-${String(matchedMonth + 1).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;
  const name = monthNames[matchedMonth];
  periodLabel = `${name.charAt(0).toUpperCase() + name.slice(1)} ${year}`;
} else if (/last\s*(1\s*)?week|past\s*week|7\s*days/.test(cmd)) {
  const d = new Date(now); d.setDate(d.getDate() - 7);
  startDate = d.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  endDate = todayStr; periodLabel = 'Last 7 Days';
} else if (/last\s*(1\s*)?month|past\s*month|30\s*days/.test(cmd)) {
  const d = new Date(now); d.setDate(d.getDate() - 30);
  startDate = d.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  endDate = todayStr; periodLabel = 'Last 30 Days';
} else if (cmd.includes('this month')) {
  startDate = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`;
  endDate = todayStr; periodLabel = 'This Month';
} else if (cmd.includes('today')) {
  startDate = todayStr; endDate = todayStr; periodLabel = 'Today';
} else {
  const d = new Date(now); d.setDate(d.getDate() - 30);
  startDate = d.toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  endDate = todayStr; periodLabel = 'Last 30 Days';
}

let accountType = 'both';
if (/credit\s*card|creditcard|\bcc\b/.test(cmd)) {
  accountType = 'credit';
} else if (/saving|\bsa\b/.test(cmd)) {
  accountType = 'savings';
}

let accountNameFilter = '';
const bankMatch = cmd.match(/\b(hdfc|icici|sbi|axis|kotak|yes\s*bank|rbl|idfc|bob|pnb|canara|federal|indusind|citi|au\s*(?:bank|sf)?)\b/i);
if (bankMatch) accountNameFilter = bankMatch[1].trim();

return [{ json: { chatId, accountType, accountNameFilter, startDate, endDate, periodLabel, rawCmd: cmd } }];

const params = $('Parse Statement Command').first().json;
const { accountType, accountNameFilter, startDate, endDate, periodLabel, chatId } = params;

// Tag rows by source sheet
const allRows = $input.all().map(item => {
  const row = { ...item.json };
  row._sheet = (row.statementYear !== undefined && row.statementYear !== null && String(row.statementYear).trim() !== '') ? 'credit' : 'savings';
  return row;
});

// Filter by account type
let filtered = allRows;
if (accountType === 'credit') filtered = allRows.filter(r => r._sheet === 'credit');
else if (accountType === 'savings') filtered = allRows.filter(r => r._sheet === 'savings');

// Filter by account/bank name
if (accountNameFilter) {
  const fl = accountNameFilter.toLowerCase();
  filtered = filtered.filter(r =>
    (r.accountName || '').toLowerCase().includes(fl) ||
    (r.bankName || '').toLowerCase().includes(fl)
  );
}

// Filter by date range
filtered = filtered.filter(r => {
  const year = parseInt(r.transactionYear);
  const month = parseInt(r.transactionMonth);
  const day = parseInt(r.transactionDay);
  if (isNaN(year) || isNaN(month) || isNaN(day)) return false;
  const rowDate = `${year}-${String(month).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
  return rowDate >= startDate && rowDate <= endDate;
});

if (filtered.length === 0) {
  return [{ json: { chatId, geminiBody: null, noData: true, periodLabel, accountType, transactionCount: 0, totalDebit: 0, totalCredit: 0 } }];
}

// Totals
const amt = r => parseFloat(r.amount) || 0;
const isDebit = r => (r.creditDebit || '').toLowerCase() === 'debit';
const isCredit = r => (r.creditDebit || '').toLowerCase() === 'credit';
const totalDebit = filtered.filter(isDebit).reduce((s, r) => s + amt(r), 0);
const totalCredit = filtered.filter(isCredit).reduce((s, r) => s + amt(r), 0);

// Aggregate by category (spend only)
const catMap = {};
filtered.filter(isDebit).forEach(r => {
  const cat = (r.category || 'Uncategorized').trim();
  if (!catMap[cat]) catMap[cat] = { debit: 0, count: 0, subs: {} };
  catMap[cat].debit += amt(r);
  catMap[cat].count++;
  const sub = (r.subCategory || '').trim();
  if (sub) { catMap[cat].subs[sub] = (catMap[cat].subs[sub] || 0) + amt(r); }
});
const catList = Object.entries(catMap)
  .sort((a, b) => b[1].debit - a[1].debit)
  .map(([cat, s]) => {
    const topSubs = Object.entries(s.subs).sort((a,b)=>b[1]-a[1]).slice(0,3)
      .map(([k,v])=>`${k}: ₹${v.toFixed(0)}`).join(', ');
    return `${cat}: ₹${s.debit.toFixed(0)} (${s.count} txns)${topSubs ? ' [' + topSubs + ']' : ''}`;
  });

// Aggregate by account
const accMap = {};
filtered.forEach(r => {
  const key = `${r.bankName || 'Unknown'} / ${r.accountName || 'Unknown'} (${r._sheet === 'credit' ? 'CC' : 'Savings'})`;
  if (!accMap[key]) accMap[key] = { debit: 0, credit: 0, count: 0 };
  accMap[key].count++;
  if (isDebit(r)) accMap[key].debit += amt(r);
  else accMap[key].credit += amt(r);
});
const accList = Object.entries(accMap)
  .sort((a, b) => b[1].debit - a[1].debit)
  .map(([acc, s]) => `${acc}: Out ₹${s.debit.toFixed(0)}, In ₹${s.credit.toFixed(0)}, ${s.count} txns`);

// Top 15 debit transactions
const topDebits = filtered.filter(isDebit)
  .sort((a, b) => amt(b) - amt(a)).slice(0, 15)
  .map(r => `₹${amt(r).toFixed(0)} - ${(r.description || '').substring(0,60)} (${r.transactionDate || ''}, ${r.category || ''})`);

// Monthly spend trend (by week or by sub-period)
const weekMap = {};
filtered.filter(isDebit).forEach(r => {
  const day = parseInt(r.transactionDay) || 1;
  const week = `Week ${Math.ceil(day/7)}`;
  weekMap[week] = (weekMap[week] || 0) + amt(r);
});
const weekTrend = Object.entries(weekMap).sort((a,b)=>a[0].localeCompare(b[0]))
  .map(([w,v])=>`${w}: ₹${v.toFixed(0)}`).join(' | ');

const accountLabel = accountType === 'both' ? 'All Accounts (Savings + CC)'
  : accountType === 'credit' ? 'Credit Card Only' : 'Savings Account Only';

const prompt = `You are a personal finance analyst. Analyze this pre-aggregated ${periodLabel} transaction data and give a thorough, insightful analysis.\n\nACCOUNT FILTER: ${accountLabel}${accountNameFilter ? ' | ' + accountNameFilter : ''}\nTOTAL TRANSACTIONS: ${filtered.length}\nTOTAL SPENT (Debits): ₹${totalDebit.toFixed(2)}\nTOTAL RECEIVED (Credits): ₹${totalCredit.toFixed(2)}\nNET: ₹${(totalCredit - totalDebit).toFixed(2)}\n\nSPEND BY CATEGORY (all ${catList.length} categories, sorted by spend):\n${catList.join('\n')}\n\nACCOUNT-WISE BREAKDOWN:\n${accList.join('\n')}\n\nTOP 15 TRANSACTIONS BY AMOUNT:\n${topDebits.join('\n')}\n\nWEEKLY SPEND TREND:\n${weekTrend}\n\nWrite a thorough plain text analysis (no markdown symbols like * _ # etc). Use these exact emoji section headers:\n\n📊 Summary\n(Overall spend, income, net, and what it means)\n\n🏷️ Category Breakdown\n(ALL categories with amounts and % of total spend, highlight top spenders)\n\n🏦 Account-wise Breakdown\n(Each account's spend vs income)\n\n🔍 Top Transactions\n(Notable large spends, any recurring patterns)\n\n📈 Spending Patterns\n(Weekly trend, recurring merchants, habits)\n\n💡 Recommendations\n(3-4 specific actionable tips based on the actual data)\n\nBe specific with rupee amounts. No filler text. Total response must fit in 4000 characters.`;

return [{ json: {
  chatId, noData: false, periodLabel,
  transactionCount: filtered.length, totalDebit, totalCredit,
  geminiBody: {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { temperature: 0.1, maxOutputTokens: 4096 }
  }
}}];

const geminiResponse = $input.first().json;
const fd = $('Filter & Build Gemini Prompt').first().json;

let analysisText = '';
if (geminiResponse.candidates && geminiResponse.candidates[0]) {
  const parts = geminiResponse.candidates[0].content?.parts;
  if (parts && parts[0]) analysisText = parts[0].text || '';
}

if (!analysisText) analysisText = 'Could not generate analysis. Please try again.';

// Strip markdown symbols that break Telegram plain-text sends
analysisText = analysisText.replace(/[*_`\[\]]/g, '');

const debitStr = '₹' + fd.totalDebit.toFixed(0);
const creditStr = '₹' + fd.totalCredit.toFixed(0);
const header = `📊 Statement Analysis — ${fd.periodLabel}\n${fd.transactionCount} transactions | Out: ${debitStr} | In: ${creditStr}\n${'-'.repeat(32)}\n`;

const LIMIT = 4096;
const fullMessage = header + analysisText;

// Split into chunks of max 4096 chars, breaking at newlines where possible
const chunks = [];
let remaining = fullMessage;
while (remaining.length > 0) {
  if (remaining.length <= LIMIT) {
    chunks.push(remaining);
    break;
  }
  // Find last newline before limit
  let cutAt = remaining.lastIndexOf('\n', LIMIT - 1);
  if (cutAt <= 0) cutAt = LIMIT - 1;
  chunks.push(remaining.substring(0, cutAt));
  remaining = remaining.substring(cutAt + 1).trimStart();
}

// Return one item per chunk so n8n sends them sequentially
return chunks.map(chunk => ({ json: { chatId: fd.chatId, reply: chunk } }));
